@page "/patients"
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Patients - VetClinic</PageTitle>

<h2>Patient Records</h2>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowNewOwnerForm">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowNewPetForm">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "Register New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary" @onclick="CancelOwnerForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="editingPet.Species" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-control" @bind-Value="editingPet.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="mt-2">
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary" @onclick="CancelPetForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (selectedPet != null)
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between">
            <span><strong>@selectedPet.Name</strong> — @selectedPet.Species @(selectedPet.Breed != null ? $"({selectedPet.Breed})" : "") | Owner: @selectedPet.Owner.FullName</span>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedPet = null">Close</button>
        </div>
        <div class="card-body">
            <h5>Medical History & Treatment Notes</h5>
            <button class="btn btn-sm btn-success mb-2" @onclick="ShowTreatmentForm">+ Add Treatment</button>

            @if (showTreatmentForm)
            {
                <EditForm Model="editingTreatment" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                    <DataAnnotationsValidator />
                    <div class="row mb-2">
                        <div class="col-md-3">
                            <InputDate class="form-control" @bind-Value="treatmentDate" />
                        </div>
                        <div class="col-md-3">
                            <InputText class="form-control" placeholder="Description" @bind-Value="editingTreatment.Description" />
                        </div>
                        <div class="col-md-2">
                            <InputText class="form-control" placeholder="Veterinarian" @bind-Value="editingTreatment.Veterinarian" />
                        </div>
                        <div class="col-md-2">
                            <InputNumber class="form-control" placeholder="Cost" @bind-Value="editingTreatment.Cost" />
                        </div>
                        <div class="col-md-2">
                            <button type="submit" class="btn btn-primary btn-sm">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="() => showTreatmentForm = false">Cancel</button>
                        </div>
                    </div>
                    <div class="row mb-2">
                        <div class="col">
                            <InputTextArea class="form-control" placeholder="Notes..." @bind-Value="editingTreatment.Notes" rows="2" />
                        </div>
                    </div>
                </EditForm>
            }

            @if (selectedPet.Treatments.Any())
            {
                <table class="table table-sm table-striped">
                    <thead><tr><th>Date</th><th>Description</th><th>Vet</th><th>Notes</th><th>Cost</th></tr></thead>
                    <tbody>
                        @foreach (var t in selectedPet.Treatments.OrderByDescending(t => t.Date))
                        {
                            <tr>
                                <td>@t.Date.ToString("d")</td>
                                <td>@t.Description</td>
                                <td>@t.Veterinarian</td>
                                <td>@t.Notes</td>
                                <td>@t.Cost.ToString("C")</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No treatments recorded.</p>
            }
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>DOB</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in filteredPets)
        {
            <tr class="@(selectedPet?.Id == pet.Id ? "table-active" : "")">
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>@pet.DateOfBirth?.ToString("d")</td>
                <td>
                    <button class="btn btn-sm btn-info" @onclick="() => SelectPet(pet)">View</button>
                    <button class="btn btn-sm btn-warning" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (!filteredPets.Any())
{
    <p class="text-muted">No patients found. Register a new pet to get started.</p>
}

@code {
    private List<Pet> pets = [];
    private List<Pet> filteredPets = [];
    private List<Owner> owners = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm, showTreatmentForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Treatment editingTreatment = new();
    private DateOnly treatmentDate = DateOnly.FromDateTime(DateTime.Today);
    private Pet? selectedPet;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        pets = await Db.Pets.Include(p => p.Owner).Include(p => p.Treatments).OrderBy(p => p.Name).ToListAsync();
        ApplyFilter();
    }

    private void Search() => ApplyFilter();

    private void ApplyFilter()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            filteredPets = pets;
        else
            filteredPets = pets.Where(p =>
                p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
                .ToList();
    }

    private void ShowNewOwnerForm() { editingOwner = new(); showOwnerForm = true; }
    private void CancelOwnerForm() => showOwnerForm = false;

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        else
            Db.Owners.Update(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private void ShowNewPetForm() { editingPet = new(); showPetForm = true; }
    private void CancelPetForm() => showPetForm = false;

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
    }

    private async Task SavePet()
    {
        if (editingPet.Id == 0)
            Db.Pets.Add(editingPet);
        else
            Db.Pets.Update(editingPet);
        await Db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task SelectPet(Pet pet)
    {
        selectedPet = await Db.Pets
            .Include(p => p.Owner)
            .Include(p => p.Treatments)
            .FirstOrDefaultAsync(p => p.Id == pet.Id);
    }

    private void ShowTreatmentForm()
    {
        editingTreatment = new() { PetId = selectedPet!.Id };
        treatmentDate = DateOnly.FromDateTime(DateTime.Today);
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        editingTreatment.PetId = selectedPet!.Id;
        editingTreatment.Date = treatmentDate.ToDateTime(TimeOnly.MinValue);
        Db.Treatments.Add(editingTreatment);
        await Db.SaveChangesAsync();
        showTreatmentForm = false;
        await SelectPet(selectedPet!);
    }
}

