@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Appointments - VetClinic</PageTitle>

<h2>Appointment Scheduling</h2>

<div class="row">
    <div class="col-md-8">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <button class="btn btn-sm btn-outline-secondary" @onclick="PrevWeek">&lt; Prev</button>
                <strong class="mx-2">@weekStart.ToString("MMM d") — @weekStart.AddDays(6).ToString("MMM d, yyyy")</strong>
                <button class="btn btn-sm btn-outline-secondary" @onclick="NextWeek">Next &gt;</button>
            </div>
            <button class="btn btn-primary" @onclick="ShowNewAppointmentForm">+ New Appointment</button>
        </div>

        <!-- Weekly calendar grid -->
        <div class="table-responsive">
            <table class="table table-bordered table-sm">
                <thead>
                    <tr>
                        <th style="width:60px">Time</th>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            <th class="text-center @(day.Date == DateTime.Today ? "table-primary" : "")">
                                @day.ToString("ddd M/d")
                            </th>
                        }
                    </tr>
                </thead>
                <tbody>
                    @for (int hour = 8; hour <= 18; hour++)
                    {
                        <tr>
                            <td class="text-muted small">@($"{hour:00}:00")</td>
                            @for (int d = 0; d < 7; d++)
                            {
                                var slotTime = weekStart.AddDays(d).AddHours(hour);
                                var slotAppts = weekAppointments.Where(a =>
                                    a.StartTime <= slotTime && a.EndTime > slotTime &&
                                    a.Status != AppointmentStatus.Cancelled).ToList();
                                var isAvailable = slotAppts.Count < 3; // max 3 concurrent appointments
                                <td class="@(isAvailable ? "" : "table-danger") small" style="cursor:pointer"
                                    @onclick="() => ClickSlot(slotTime)">
                                    @foreach (var appt in slotAppts)
                                    {
                                        <div class="badge bg-@(appt.Status == AppointmentStatus.Completed ? "secondary" : "success") text-truncate d-block mb-1"
                                             style="max-width:100px; cursor:pointer" @onclick="() => SelectAppointment(appt)" @onclick:stopPropagation="true">
                                            @appt.Pet.Name
                                        </div>
                                    }
                                </td>
                            }
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <div class="col-md-4">
        @if (showForm)
        {
            <div class="card">
                <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
                <div class="card-body">
                    <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                        <DataAnnotationsValidator />
                        <ValidationSummary />

                        <div class="mb-2">
                            <label class="form-label">Patient</label>
                            <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                                <option value="0">-- Select Pet --</option>
                                @foreach (var pet in pets)
                                {
                                    <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Start Time</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">End Time</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.EndTime" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reason</label>
                            <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Notes</label>
                            <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" rows="2" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Status</label>
                            <InputSelect class="form-control" @bind-Value="editingAppointment.Status">
                                @foreach (var s in Enum.GetValues<AppointmentStatus>())
                                {
                                    <option value="@s">@s</option>
                                }
                            </InputSelect>
                        </div>

                        <button type="submit" class="btn btn-primary">Save</button>
                        @if (editingAppointment.Id != 0)
                        {
                            <button type="button" class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
                        }
                        <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Close</button>
                    </EditForm>
                </div>
            </div>
        }

        @if (selectedAppointment != null && !showForm)
        {
            <div class="card">
                <div class="card-header">Appointment Details</div>
                <div class="card-body">
                    <p><strong>Patient:</strong> @selectedAppointment.Pet.Name</p>
                    <p><strong>Time:</strong> @selectedAppointment.StartTime.ToString("g") — @selectedAppointment.EndTime.ToString("t")</p>
                    <p><strong>Reason:</strong> @selectedAppointment.Reason</p>
                    <p><strong>Vet:</strong> @selectedAppointment.Veterinarian</p>
                    <p><strong>Status:</strong> <span class="badge bg-@StatusColor(selectedAppointment.Status)">@selectedAppointment.Status</span></p>
                    @if (!string.IsNullOrEmpty(selectedAppointment.Notes))
                    {
                        <p><strong>Notes:</strong> @selectedAppointment.Notes</p>
                    }
                    <button class="btn btn-warning btn-sm" @onclick="() => EditAppointment(selectedAppointment)">Reschedule / Edit</button>
                    @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
                    {
                        <button class="btn btn-danger btn-sm" @onclick="CancelSelected">Cancel</button>
                    }
                </div>
            </div>
        }
    </div>
</div>

@code {
    private List<Appointment> weekAppointments = [];
    private List<Pet> pets = [];
    private DateTime weekStart;
    private bool showForm;
    private Appointment editingAppointment = new();
    private Appointment? selectedAppointment;

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        await LoadData();
    }

    private async Task LoadData()
    {
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
            .ToListAsync();
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task PrevWeek() { weekStart = weekStart.AddDays(-7); await LoadData(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadData(); }

    private void ClickSlot(DateTime slotTime)
    {
        editingAppointment = new()
        {
            StartTime = slotTime,
            EndTime = slotTime.AddHours(1)
        };
        showForm = true;
        selectedAppointment = null;
    }

    private void ShowNewAppointmentForm()
    {
        editingAppointment = new()
        {
            StartTime = DateTime.Today.AddHours(9),
            EndTime = DateTime.Today.AddHours(10)
        };
        showForm = true;
        selectedAppointment = null;
    }

    private void SelectAppointment(Appointment appt)
    {
        selectedAppointment = appt;
        showForm = false;
    }

    private void EditAppointment(Appointment appt)
    {
        editingAppointment = appt;
        showForm = true;
        selectedAppointment = null;
    }

    private async Task SaveAppointment()
    {
        if (editingAppointment.Id == 0)
            Db.Appointments.Add(editingAppointment);
        else
            Db.Appointments.Update(editingAppointment);
        await Db.SaveChangesAsync();
        showForm = false;
        await LoadData();
    }

    private async Task CancelAppointment()
    {
        editingAppointment.Status = AppointmentStatus.Cancelled;
        Db.Appointments.Update(editingAppointment);
        await Db.SaveChangesAsync();
        showForm = false;
        await LoadData();
    }

    private async Task CancelSelected()
    {
        selectedAppointment!.Status = AppointmentStatus.Cancelled;
        Db.Appointments.Update(selectedAppointment);
        await Db.SaveChangesAsync();
        selectedAppointment = null;
        await LoadData();
    }

    private static string StatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "secondary",
        AppointmentStatus.Cancelled => "danger",
        _ => "light"
    };
}

