                                       @bind="invoiceItems[idx].Quantity" />
                            </div>
                            <div class="col-md-3">
                                <input type="number" step="0.01" class="form-control form-control-sm" placeholder="Unit Price"
                                       @bind="invoiceItems[idx].UnitPrice" />
                            </div>
                            <div class="col-md-2">
                                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceItems.RemoveAt(idx)">✕</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-secondary mb-2" @onclick="AddLineItem">+ Add Item</button>
                    <div class="fw-bold mb-2">Total: @invoiceItems.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</div>

                    <button type="submit" class="btn btn-primary">Save Invoice</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Owner</th><th>Issued</th><th>Due</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.Owner.FullName</td>
                    <td>@inv.IssuedDate.ToString("d")</td>
                    <td>@inv.DueDate?.ToString("d")</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.AmountPaid.ToString("C")</td>
                    <td class="@(inv.BalanceDue > 0 ? "text-danger fw-bold" : "text-success")">@inv.BalanceDue.ToString("C")</td>
                    <td><span class="badge bg-@InvoiceStatusColor(inv.Status)">@inv.Status</span></td>
                    <td>
                        <button class="btn btn-sm btn-info" @onclick="() => SelectInvoice(inv)">Details</button>
                        <button class="btn btn-sm btn-success" @onclick="() => ShowPaymentForm(inv)">Pay</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (selectedInvoice != null)
    {
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between">
                <span>Invoice #@selectedInvoice.Id — @selectedInvoice.Owner.FullName</span>
                <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedInvoice = null">Close</button>
            </div>
            <div class="card-body">
                <table class="table table-sm">
                    <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Line Total</th></tr></thead>
                    <tbody>
                        @foreach (var item in selectedInvoice.Items)
                        {
                            <tr>
                                <td>@item.Description</td>
                                <td>@item.Quantity</td>
                                <td>@item.UnitPrice.ToString("C")</td>
                                <td>@item.LineTotal.ToString("C")</td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    }
}

@if (activeTab == "payments")
{
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th><th>Type</th></tr>
        </thead>
        <tbody>
            @foreach (var p in allPayments)
            {
                <tr>
                    <td>@p.Date.ToString("g")</td>
                    <td>@p.InvoiceId</td>
                    <td>@p.Invoice.Owner.FullName</td>
                    <td class="@(p.IsRefund ? "text-danger" : "")">@((p.IsRefund ? "-" : "") + p.Amount.ToString("C"))</td>
                    <td>@p.Method</td>
                    <td>@p.Reference</td>
                    <td>@(p.IsRefund ? "Refund" : "Payment")</td>
                </tr>
            }
        </tbody>
    </table>
    @if (!allPayments.Any())
    {
        <p class="text-muted">No payments recorded.</p>
    }
}

@if (showPaymentForm)
{
    <div class="modal d-block" tabindex="-1" style="background:rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Process Payment — Invoice #@paymentInvoice!.Id</h5>
                    <button class="btn-close" @onclick="() => showPaymentForm = false"></button>
                </div>
                <div class="modal-body">
                    <p>Balance Due: <strong>@paymentInvoice!.BalanceDue.ToString("C")</strong></p>
                    <EditForm Model="editingPayment" OnValidSubmit="SavePayment" FormName="paymentForm">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="editingPayment.Amount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-control" @bind-Value="editingPayment.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="editingPayment.Reference" />
                        </div>
                        <div class="form-check mb-2">
                            <InputCheckbox class="form-check-input" @bind-Value="editingPayment.IsRefund" />
                            <label class="form-check-label">This is a refund</label>
                        </div>
                        <button type="submit" class="btn btn-success">Process Payment</button>
                        <button type="button" class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                    </EditForm>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string statusFilter = "";
    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private List<Payment> allPayments = [];
    private bool showInvoiceForm, showPaymentForm;
    private Invoice editingInvoice = new();
    private List<InvoiceItem> invoiceItems = [];
    private Invoice? selectedInvoice;
    private Invoice? paymentInvoice;
    private Payment editingPayment = new();

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();

        var query = Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (Enum.TryParse<InvoiceStatus>(statusFilter, out var s))
            query = query.Where(i => i.Status == s);

        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();

        allPayments = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    private void ShowNewInvoiceForm()
    {
        editingInvoice = new() { IssuedDate = DateTime.Now, DueDate = DateTime.Now.AddDays(30) };
        invoiceItems = [new InvoiceItem()];
        showInvoiceForm = true;
    }

    private void AddLineItem() => invoiceItems.Add(new InvoiceItem());

    private async Task SaveInvoice()
    {
        editingInvoice.TotalAmount = invoiceItems.Sum(i => i.Quantity * i.UnitPrice);
        if (editingInvoice.Id == 0)
        {
            Db.Invoices.Add(editingInvoice);
            await Db.SaveChangesAsync();
            foreach (var item in invoiceItems)
            {
                item.InvoiceId = editingInvoice.Id;
                Db.InvoiceItems.Add(item);
            }
        }
        else
        {
            Db.Invoices.Update(editingInvoice);
        }
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void SelectInvoice(Invoice inv) => selectedInvoice = inv;

    private void ShowPaymentForm(Invoice inv)
    {
        paymentInvoice = inv;
        editingPayment = new()
        {
            InvoiceId = inv.Id,
            Amount = inv.BalanceDue,
            Date = DateTime.Now
        };
        showPaymentForm = true;
    }

    private async Task SavePayment()
    {
        editingPayment.InvoiceId = paymentInvoice!.Id;
        editingPayment.Date = DateTime.Now;
        Db.Payments.Add(editingPayment);

        // Auto-update invoice status
        var totalPaid = paymentInvoice.AmountPaid + (editingPayment.IsRefund ? -editingPayment.Amount : editingPayment.Amount);
        if (totalPaid >= paymentInvoice.TotalAmount)
            paymentInvoice.Status = InvoiceStatus.Paid;
        else if (totalPaid > 0)
            paymentInvoice.Status = InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private static string InvoiceStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "light"
    };
}

